int array_find_last_equal(int n, int *a, int k)
/*@ With l
    Require
      0 <= n &&
      Zlength(l) == n &&
      IntArray::full(a, n, l)
    Ensure
      ((
        __return == -1 &&
        (forall (i: Z), (0 <= i && i < n) => l[i] != k)
      ) || (
        0 <= __return &&
        __return < n &&
        l[__return] == k &&
        (forall (i: Z), (__return < i && i < n) => l[i] != k)
      )) &&
      IntArray::full(a, n, l)
*/
{
    int i;
    int ans = -1;

    for (i = 0; i < n; ++i) {
        if (a[i] == k) {
            ans = i;
        }
    }

    return ans;
}

